// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastDay[];
}

export interface WeatherHookReturn {
  formattedTemp: string;
  conditionIcon: string;
  formattedHumidity: string;
  formattedWind: string;
  forecastData: ForecastDay[];
}

export interface ForecastItemProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit: string;
}

export interface WeatherDetailProps {
  label: string;
  value: string | number;
  icon?: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const CONDITION_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Clear': '☀️',
  'Cloudy': '☁️',
  'Partly Cloudy': '⛅',
  'Rainy': '🌧️',
  'Showers': '🌦️',
  'Stormy': '⛈️',
  'Snowy': '❄️',
  'Mist': '🌫️',
  'Fog': '🌫️',
};

export const FALLBACK_ICON = '❓';

export const DEFAULT_UNIT = 'C';

export const DEFAULT_CITY = 'London';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherHookReturn } from './types';
import * as constants from './constants';

/**
 * Custom hook to process and format weather data for the WeatherCard component.
 * Handles temperature rounding, unit appending, and icon mapping.
 * 
 * @param props - The weather data and configuration props
 * @returns Formatted weather values and icons
 */
export function useWeather(props: WeatherCardProps): WeatherHookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = []
  } = props;

  // Format temperature by rounding and appending the unit (C or F)
  const formattedTemp = useMemo(() => {
    const rounded = Math.round(temperature);
    return `${rounded}°${unit}`;
  }, [temperature, unit]);

  // Format humidity as a percentage string
  const formattedHumidity = useMemo(() => {
    return `${Math.round(humidity)}%`;
  }, [humidity]);

  // Format wind speed with km/h suffix
  const formattedWind = useMemo(() => {
    return `${windSpeed} km/h`;
  }, [windSpeed]);

  // Find the appropriate icon for the current weather condition from constants
  const conditionIcon = useMemo(() => {
    // Assuming constants might have WEATHER_ICONS or CONDITION_ICONS
    const icons = (constants as any).WEATHER_ICONS || (constants as any).CONDITION_ICONS || {};
    const key = condition.toLowerCase().trim();
    return icons[key] || 'sun'; // Default to 'sun' if condition not found
  }, [condition]);

  return {
    formattedTemp,
    conditionIcon,
    formattedHumidity,
    formattedWind,
    forecastData: forecast,
  };
}


