import React from 'react';
import { Stack, Text, Image } from '@ggui-ai/design/primitives';
import type { ForecastItemProps } from './types';

/**
 * ForecastItem — A vertical sub-component for a single day in the weather forecast.
 * Displays the day name, weather icon, and high/low temperatures.
 */
export function ForecastItem({ day, icon, high, low, unit }: ForecastItemProps) {
  return (
    <Stack align="center" gap={8}>
      <Text 
        variant="label" 
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {day}
      </Text>

      <Image
        src={icon}
        alt={day}
        width={40}
        height={40}
        objectFit="contain"
      />

      <Stack align="center" gap={2}>
        <Text 
          weight="bold" 
          size="base" 
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {high}°{unit}
        </Text>
        <Text 
          variant="caption" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
}


// --- WeatherDetail.tsx ---
import React from 'react';
import { Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { WeatherDetailProps } from './types';

/**
 * WeatherDetail component
 * Displays a single weather metric (e.g., Humidity, Wind Speed) with an optional icon.
 */
export function WeatherDetail({ label, value, icon }: WeatherDetailProps) {
  return (
    <Stack gap="var(--ggui-spacing-1, 4px)" align="start">
      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
        {icon && (
          <Icon 
            name={icon} 
            size={16} 
            color="var(--ggui-color-onSurfaceVariant, #52525b)" 
          />
        )}
        <Text 
          variant="caption" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          as="span"
        >
          {label}
        </Text>
      </Stack>
      <Text 
        variant="body" 
        weight="semibold" 
        color="var(--ggui-color-onSurface, #18181b)"
      >
        {value}
      </Text>
    </Stack>
  );
}


// --- ui.tsx ---
import React from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';
import type {
  WeatherCardProps,
  WeatherHookReturn,
  ForecastItemProps,
  WeatherDetailProps,
} from './types';

// Internal component for weather details (Humidity, Wind Speed, etc.)
const WeatherDetail = ({ label, value, icon }: WeatherDetailProps) => {
  return (
    <Stack gap="var(--ggui-spacing-1, 4px)" align="center" style={{ flex: 1 }}>
      {icon && <Text size="xl">{icon}</Text>}
      <Text
        variant="caption"
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {label}
      </Text>
      <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
        {value}
      </Text>
    </Stack>
  );
};

// Internal component for daily forecast items
const ForecastItem = ({ day, icon, high, low }: ForecastItemProps) => {
  return (
    <Box
      padding="var(--ggui-spacing-3, 12px)"
      borderRadius="var(--ggui-shape-radius-md, 8px)"
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      style={{ minWidth: '80px', flex: 1 }}
    >
      <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
        <Text
          variant="label"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {day}
        </Text>
        <Text size="2xl">{icon}</Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" justify="center">
          <Text variant="bodySmall" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {high}°
          </Text>
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {low}°
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
};

export function ComponentUI({
  city,
  unit = 'C',
  formattedTemp,
  conditionIcon,
  condition,
  formattedHumidity,
  formattedWind,
  forecastData,
}: WeatherCardProps & WeatherHookReturn) {
  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-4, 16px)">
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        shadow="md"
        radius="xl"
        border={true}
      >
        <Stack gap="var(--ggui-spacing-6, 24px)">
          {/* Header Section */}
          <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
            <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3, 12px)">
              <Text size="4xl" weight="bold">
                {conditionIcon}
              </Text>
              <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
                {formattedTemp}
              </Heading>
            </Stack>
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Details Section */}
          <Stack direction="horizontal" justify="between" align="center">
            <WeatherDetail label="Humidity" value={formattedHumidity} icon="💧" />
            <Divider
              orientation="vertical"
              margin="var(--ggui-spacing-4, 16px)"
              color="var(--ggui-color-outlineVariant, #e4e4e7)"
            />
            <WeatherDetail label="Wind" value={formattedWind} icon="💨" />
          </Stack>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Forecast Section */}
          <Stack gap="var(--ggui-spacing-3, 12px)">
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              5-Day Forecast
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
              {forecastData.map((item, index) => (
                <ForecastItem
                  key={`${item.day}-${index}`}
                  day={item.day}
                  icon={item.icon}
                  high={item.high}
                  low={item.low}
                  unit={unit}
                />
              ))}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
